<style lang="scss">

body {
    background: $home_bg;
}

.image_wrapper {
    background: $light-grey;
    border-radius: 20px;
    width: 100%;
    display: flex;
    justify-content: center;
    align-items: center;
    height: calc(60vh - 96px - 47px);
    svg {
        max-height: 80%;
        width: auto;
    }
}

.hello_wrapper {
    height: calc(40vh - 10px);
    background: $dark;
    padding: 20px 0 40px;
    border-radius: 20px;
    margin-top: 10px;
    display: flex;
    justify-content: center;
    flex-direction: column;
    align-items: center;
    h1 {
        font-weight: 600;
        font-size: 28px;
        line-height: 120%;
        color: $light-grey;
        text-align: center;
        margin-bottom: 10px;
    }
    p {
        font-weight: 400;
        font-size: 14px;
        line-height: 120%;
        text-align: center;
        color: $grey;
        margin-bottom: 50px;
    }
    .button {
        margin-bottom: 30px;
    }
    .link {
        font-weight: 500;
        font-size: 16px;
        line-height: 120%;
        color: $light-grey;
    }
}

</style>
